// 모든 Go 파일은 패키지 선언 필수!
package main

import (
    "fmt"      // 표준 라이브러리
    "strings"  // 문자열 처리
    "time"     // 시간 관련
)

func main() {
    fmt.Println("Hello, Go!")
    fmt.Println(strings.ToUpper("go"))
    fmt.Println(time.Now())
}

// 터미널에서 모듈 초기화
// $ go mod init github.com/user/app

// go.mod 파일 (자동 생성)
module github.com/user/app

go 1.21

require (
    github.com/gin-gonic/gin v1.9.1
)

// 의존성 설치
// $ go get github.com/gin-gonic/gin
// $ go mod tidy  // 정리!

package user

// 대문자 = 외부 공개 (exported) ✅
type User struct {
    Name  string // 공개
    Email string // 공개
    age   int    // 비공개!
}

// 공개 함수
func NewUser(name string) *User {
    return &User{Name: name, age: 0}
}

// 비공개 함수 (패키지 내부용)
func validate(email string) bool {
    return len(email) > 0
}

// 프로젝트 구조
// myapp/
//   go.mod
//   main.go
//   calc/
//     math.go

// calc/math.go
package calc

func Add(a, b int) int { return a+b }
func Mul(a, b int) int { return a*b }

// main.go
package main
import "myapp/calc"
func main() {
    fmt.Println(calc.Add(3, 5)) // 8
}

package config

var Settings map[string]string

// init: 패키지 로드 시 자동 실행!
func init() {
    Settings = map[string]string{
        "env": "production",
    }
    fmt.Println("설정 초기화 완료!")
}

// 별칭 import 활용
